// ════════════════════════════════════════════════════════
//  GeoJSON name → Gallup data key mapping
// ════════════════════════════════════════════════════════
const NAME_MAP = {
    "United States of America":                 "United States",
    "United Kingdom of Great Britain and Northern Ireland": "United Kingdom",
    "Republic of Korea":                        "South Korea",
    "Korea":                                    "South Korea",
    "Democratic Republic of the Congo":         "Democratic Republic of the Congo",
    "Republic of the Congo":                    "Republic of the Congo",
    "Congo":                                    "Republic of the Congo",
    "Côte d'Ivoire":                            "Côte d'Ivoire",
    "Taiwan":                                   "Taiwan (Province of China)",
    "Hong Kong":                                "Hong Kong (S.A.R. of China)",
    "Bosnia and Herz.":                         "Bosnia and Herzegovina",
    "Dominican Rep.":                           "Dominican Republic",
    "eSwatini":                                 "Eswatini",
    "Palestine":                                "Palestinian Territories",
    "Turkiye":                                  "Türkiye",
    "Turkey":                                   "Türkiye",
    "N. Cyprus":                                "Northern Cyprus",
    "Gambia":                                   "The Gambia",
    "Kosovo":                                   "Kosovo",
    "Macedonia":                                "North Macedonia",
    "North Macedonia":                          "North Macedonia",
    "Myanmar":                                  "Myanmar",
    "Laos":                                     "Laos",
    "Vietnam":                                  "Vietnam",
    "S. Sudan":                                 "South Sudan",
    "Solomon Is.":                              "Solomon Islands",
};

function resolveKey(name) {
    if (!name) return null;
    return NAME_MAP[name] || name;
}

// ════════════════════════════════════════════════════════
//  STATE
// ════════════════════════════════════════════════════════
var currentMode    = "loneliness";
var selectedCountry = null;
var geoFeatures    = null;   // cached GeoJSON features
var mapCountryPaths = null;  // d3 selection of all .country paths

// ════════════════════════════════════════════════════════
//  COLOUR HELPERS
// ════════════════════════════════════════════════════════
function getVal(key) {
    if (!key) return null;
    if (currentMode === "loneliness") return GALLUP.loneliness[key]  ? GALLUP.loneliness[key].vf  : null;
    if (currentMode === "connected")  return GALLUP.connected[key]   ? GALLUP.connected[key].vf   : null;
    if (currentMode === "policies")   return POLICIES[key] ? POLICIES[key].length : 0;
    return null;
}

function getColor(key) {
    var v = getVal(key);
    if (v === null || v === undefined) return "#1a2235";

    if (currentMode === "loneliness") {
        // 5% → deep blue, 58% → deep red
        var t = Math.min(Math.max((v - 5) / 53, 0), 1);
        return d3.interpolateRgb("#1e3a5f", "#dc2626")(t);
    }
    if (currentMode === "connected") {
        // 45% → dark green, 95% → bright green
        var t = Math.min(Math.max((v - 45) / 50, 0), 1);
        return d3.interpolateRgb("#14532d", "#4ade80")(t);
    }
    if (currentMode === "policies") {
        if (v === 0) return "#1a2235";
        if (v === 1) return "#4338ca";
        if (v === 2) return "#7c3aed";
        return "#c026d3";
    }
}

// ════════════════════════════════════════════════════════
//  MODE SWITCH
// ════════════════════════════════════════════════════════
function setMode(mode) {
    currentMode = mode;
    // Update button states
    d3.selectAll(".mode-btn").classed("active", false);
    d3.select(".mode-btn[data-mode='" + mode + "']").classed("active", true);
    updateLegend();
    if (mapCountryPaths) {
        mapCountryPaths.transition().duration(400)
            .attr("fill", function(d) { return getColor(resolveKey(d.properties.name)); });
    }
    // Refresh sidebar if open
    if (selectedCountry) showSidebar(selectedCountry);
}

function updateLegend() {
    var grad  = document.getElementById("legend-grad");
    var label = document.getElementById("legend-label");
    var lo    = document.getElementById("legend-lo");
    var hi    = document.getElementById("legend-hi");
    if (currentMode === "loneliness") {
        grad.style.background  = "linear-gradient(to right,#1e3a5f,#dc2626)";
        label.textContent = "% Very/Fairly Lonely";
        lo.textContent = "Low";   hi.textContent = "High";
    } else if (currentMode === "connected") {
        grad.style.background  = "linear-gradient(to right,#14532d,#4ade80)";
        label.textContent = "% Very/Fairly Connected";
        lo.textContent = "Low";   hi.textContent = "High";
    } else {
        grad.style.background  = "linear-gradient(to right,#1a2235,#4338ca,#7c3aed,#c026d3)";
        label.textContent = "# of tracked policies";
        lo.textContent = "None";  hi.textContent = "Many";
    }
}

// ════════════════════════════════════════════════════════
//  TOOLTIP
// ════════════════════════════════════════════════════════
var tooltip = d3.select("#tooltip");

function showTooltip(event, d) {
    var key = resolveKey(d.properties.name);
    var v   = getVal(key);
    document.getElementById("tt-name").textContent = key || d.properties.name;
    if (v === null || v === undefined) {
        document.getElementById("tt-val").textContent = "No data available";
    } else if (currentMode === "policies") {
        document.getElementById("tt-val").textContent = v + " tracked " + (v === 1 ? "policy" : "policies");
    } else {
        var lbl = currentMode === "loneliness" ? "Very/Fairly Lonely" : "Very/Fairly Connected";
        document.getElementById("tt-val").textContent = v + "% " + lbl;
    }
    tooltip.style("display", "block");
    moveTooltip();
}
function moveTooltip() {
    var wrap = document.getElementById("map-wrap");
    var rect = wrap.getBoundingClientRect();
    var x = d3.event.clientX - rect.left;
    var y = d3.event.clientY - rect.top;
    var tw = 180; // approx tooltip width
    var left = (x + 14 + tw > wrap.offsetWidth) ? x - tw - 10 : x + 14;
    tooltip.style("left", left + "px").style("top", (y - 10) + "px");
}
function hideTooltip() {
    tooltip.style("display", "none");
}

// ════════════════════════════════════════════════════════
//  PIE CHARTS  (plain Canvas, no extra library needed)
// ════════════════════════════════════════════════════════
function drawPie(canvasId, slices, colors) {
    var canvas = document.getElementById(canvasId);
    if (!canvas) return;
    var size = 110;
    canvas.width  = size;
    canvas.height = size;
    var ctx    = canvas.getContext("2d");
    var total  = slices.reduce(function(a, b) { return a + b; }, 0);
    if (!total) return;
    var start  = -Math.PI / 2;
    slices.forEach(function(s, i) {
        var angle = (s / total) * 2 * Math.PI;
        ctx.beginPath();
        ctx.moveTo(size / 2, size / 2);
        ctx.arc(size / 2, size / 2, size / 2 - 2, start, start + angle);
        ctx.closePath();
        ctx.fillStyle = colors[i];
        ctx.fill();
        start += angle;
    });
    // Donut hole
    ctx.beginPath();
    ctx.arc(size / 2, size / 2, size / 3.2, 0, 2 * Math.PI);
    ctx.fillStyle = "#111827";
    ctx.fill();
    // Center label
    ctx.fillStyle  = "#e2e8f0";
    ctx.font       = "bold 13px Montserrat,sans-serif";
    ctx.textAlign  = "center";
    ctx.textBaseline = "middle";
    var pct = Math.round(slices[0] + slices[1]);
    ctx.fillText(pct + "%", size / 2, size / 2);
}

// ════════════════════════════════════════════════════════
//  STAT BAR ROW
// ════════════════════════════════════════════════════════
function statRow(label, val, color) {
    if (val === null || val === undefined) return "";
    return '<div class="stat-row">' +
        '<span class="stat-lbl">' + label + '</span>' +
        '<div class="stat-bar-wrap"><div class="stat-bar" style="width:' + val + '%;background:' + color + '"></div></div>' +
        '<span class="stat-num">' + val + '%</span>' +
        '</div>';
}

// ════════════════════════════════════════════════════════
//  SIDEBAR — show country details
// ════════════════════════════════════════════════════════
function showSidebar(countryKey) {
    selectedCountry = countryKey;
    document.getElementById("sb-country").textContent = countryKey;
    document.getElementById("sidebar").classList.add("open");
    closePolicyDetail();

    var lone  = GALLUP.loneliness[countryKey];
    var conn  = GALLUP.connected[countryKey];
    var ml    = GALLUP.men_loneliness[countryKey];
    var wl    = GALLUP.women_loneliness[countryKey];
    var mc    = GALLUP.men_connected[countryKey];
    var wc    = GALLUP.women_connected[countryKey];
    var pols  = POLICIES[countryKey] || [];

    var html = "";

    // ── Overall loneliness ──
    if (lone) {
        html += '<div class="section-label">Loneliness</div>';
        html += '<div class="stat-card">' +
            '<h4>Self-Reported Loneliness</h4>' +
            '<div class="stat-headline">Very + Fairly Lonely: <b style="color:#ef4444">' + lone.vf + '%</b></div>' +
            statRow("Very lonely",    lone.v,  "#ef4444") +
            statRow("Fairly lonely",  lone.f,  "#f97316") +
            statRow("A little",       lone.al, "#fbbf24") +
            statRow("Not at all",     lone.na, "#4ade80") +
            '</div>';
    }

    // ── Overall connection ──
    if (conn) {
        html += '<div class="section-label">Social Connection</div>';
        html += '<div class="stat-card">' +
            '<h4>Perceptions of Social Connectedness</h4>' +
            '<div class="stat-headline">Very + Fairly Connected: <b style="color:#4ade80">' + conn.vf + '%</b></div>' +
            statRow("Very connected",    conn.v,  "#4ade80") +
            statRow("Fairly connected",  conn.f,  "#06b6d4") +
            statRow("A little",          conn.al, "#3b82f6") +
            statRow("Not at all",        conn.na, "#ef4444") +
            '</div>';
    }

    // ── Gender pie charts ──
    html += '<div class="section-label">By Gender — Loneliness</div>';
    html += '<div class="charts-row">';
    if (ml) {
        html += '<div class="chart-card"><h4>♂ Men</h4><div class="chart-sub">Lonely</div>' +
            '<canvas class="piechart" id="pie-ml"></canvas></div>';
    }
    if (wl) {
        html += '<div class="chart-card"><h4>♀ Women</h4><div class="chart-sub">Lonely</div>' +
            '<canvas class="piechart" id="pie-wl"></canvas></div>';
    }
    html += '</div>';

    html += '<div class="section-label">By Gender — Connection</div>';
    html += '<div class="charts-row">';
    if (mc) {
        html += '<div class="chart-card"><h4>♂ Men</h4><div class="chart-sub">Connected</div>' +
            '<canvas class="piechart" id="pie-mc"></canvas></div>';
    }
    if (wc) {
        html += '<div class="chart-card"><h4>♀ Women</h4><div class="chart-sub">Connected</div>' +
            '<canvas class="piechart" id="pie-wc"></canvas></div>';
    }
    html += '</div>';

    // ── Policies ──
    html += '<div class="section-label" style="margin-top:16px">Policies & Initiatives</div>';
    if (pols.length === 0) {
        html += '<div class="no-policy">No tracked national or local policies found for this country.<br><br>' +
            'As of 2025, only 8 of 194 WHO member states have formal national loneliness policies.</div>';
    } else {
        pols.forEach(function(p) {
            html += '<div class="policy-item" onclick="showPolicyDetail(\'' + p.id + '\',\'' + countryKey.replace(/'/g,"\\'")+'\''+')">' +
                '<div class="policy-icon">' + p.icon + '</div>' +
                '<div class="policy-text">' +
                    '<div class="policy-tag tag-' + p.tag + '">' + p.tagLabel + '</div>' +
                    '<h5>' + p.name + '</h5>' +
                    '<p>' + p.short + '</p>' +
                '</div></div>';
        });
    }

    document.getElementById("sb-content").innerHTML = html;

    // Draw pie charts after DOM is updated
    var loneColors = ["#ef4444","#f97316","#fbbf24","#4ade80"];
    var connColors = ["#4ade80","#06b6d4","#3b82f6","#ef4444"];

    requestAnimationFrame(function() {
        if (ml) drawPie("pie-ml", [ml.v||0, ml.f||0, ml.al||0, ml.na||0], loneColors);
        if (wl) drawPie("pie-wl", [wl.v||0, wl.f||0, wl.al||0, wl.na||0], loneColors);
        if (mc) drawPie("pie-mc", [mc.v||0, mc.f||0, mc.al||0, mc.na||0], connColors);
        if (wc) drawPie("pie-wc", [wc.v||0, wc.f||0, wc.al||0, wc.na||0], connColors);
    });
}

function closeSidebar() {
    document.getElementById("sidebar").classList.remove("open");
    selectedCountry = null;
    if (mapCountryPaths) mapCountryPaths.classed("selected", false);
}

// ════════════════════════════════════════════════════════
//  POLICY DETAIL PANEL
// ════════════════════════════════════════════════════════
function showPolicyDetail(policyId, countryKey) {
    var pols = POLICIES[countryKey] || [];
    var p    = null;
    for (var i = 0; i < pols.length; i++) {
        if (pols[i].id === policyId) { p = pols[i]; break; }
    }
    if (!p) return;
    document.getElementById("pd-title").textContent = p.name;
    document.getElementById("pd-body").innerHTML    = p.detail;
    document.getElementById("policy-detail").classList.add("show");
}

function closePolicyDetail() {
    document.getElementById("policy-detail").classList.remove("show");
}

// ════════════════════════════════════════════════════════
//  MAP INITIALISATION  (d3 v5 style)
// ════════════════════════════════════════════════════════
var mapDiv = document.getElementById("map");
var mapW   = mapDiv.offsetWidth;
var mapH   = mapDiv.offsetHeight;

var projection = d3.geoNaturalEarth1()
    .scale(mapW / 6)
    .translate([mapW / 2, mapH / 1.85]);

var pathFn = d3.geoPath().projection(projection);

var mapSvg = d3.select("#map")
    .append("svg")
    .attr("width",  mapW)
    .attr("height", mapH)
    .style("cursor", "grab");

var mapG = mapSvg.append("g");

// Zoom & pan
var zoom = d3.zoom()
    .scaleExtent([0.8, 8])
    .on("zoom", function() {
        mapG.attr("transform", d3.event.transform);
    });

mapSvg.call(zoom);
mapSvg.on("mousedown.cursor", function() { mapSvg.style("cursor","grabbing"); });
mapSvg.on("mouseup.cursor",   function() { mapSvg.style("cursor","grab"); });

// Load GeoJSON from the local data folder.
d3.json("data/world.geojson")
    .then(function(geo) {
        geoFeatures = geo.features;

        mapCountryPaths = mapG.selectAll(".country")
            .data(geo.features)
            .enter()
            .append("path")
            .attr("class", "country")
            .attr("d",    pathFn)
            .attr("fill", function(d) { return getColor(resolveKey(d.properties.name)); })
            // ── hover ──
            .on("mouseover", function(d) {
                showTooltip(d3.event, d);
            })
            .on("mousemove", function() {
                moveTooltip();
            })
            .on("mouseout", function() {
                hideTooltip();
            })
            // ── click to open sidebar ──
            .on("click", function(d) {
                d3.event.stopPropagation();   // prevent svg click from also firing
                var key = resolveKey(d.properties.name);
                if (key === selectedCountry) {
                    closeSidebar();
                    return;
                }
                mapCountryPaths.classed("selected", false);
                d3.select(this).classed("selected", true);
                showSidebar(key);
            });

        // Clicking blank ocean closes sidebar
        mapSvg.on("click", function() { closeSidebar(); });
    })
    .catch(function(err) {
        console.error("Error loading GeoJSON:", err);
    });

// ════════════════════════════════════════════════════════
//  BUTTON WIRING  (mode toggle)
// ════════════════════════════════════════════════════════
d3.selectAll(".mode-btn").on("click", function() {
    setMode(d3.select(this).attr("data-mode"));
});

// Sidebar close button
document.getElementById("sb-close").addEventListener("click", closeSidebar);

// Policy-detail back button
document.getElementById("pd-back").addEventListener("click", closePolicyDetail);

// ── Init legend ──
updateLegend();
